+    data: []f32,
+    allocator: std.mem.Allocator,
+
+    pub fn init(allocator: std.mem.Allocator, size: usize) !@This() {
+        return .{
+            .data = try allocator.alloc(f32, size),
+            .allocator = allocator,
+        };
+    }
+
+    pub fn deinit(self: *@This()) void {
